import{_ as l,o as i,c as e,a0 as t}from"./chunks/framework.CSGB4SNl.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"java/eight-legged essay/java-hot200-day14.md","filePath":"java/eight-legged essay/java-hot200-day14.md"}'),r={name:"java/eight-legged essay/java-hot200-day14.md"};function o(s,a,h,n,d,c){return i(),e("div",null,[...a[0]||(a[0]=[t('<h4 id="http和https有什么区别" tabindex="-1">http和https有什么区别 <a class="header-anchor" href="#http和https有什么区别" aria-label="Permalink to &quot;http和https有什么区别&quot;">​</a></h4><ol><li>http在传输过程中都是明文的，容易被窃听和篡改，而https就是在http下面加了一个tls/ssl层用来加密-三次握手后还需要进行这个握手，只有持有钥匙的接收方才可以打开</li><li>加密解决窃听、校验解决篡改、数字证书解决冒充</li><li>占据端口不同，http是80，s是443</li></ol><h4 id="如何对java中的垃圾回收进行调优" tabindex="-1">如何对java中的垃圾回收进行调优 <a class="header-anchor" href="#如何对java中的垃圾回收进行调优" aria-label="Permalink to &quot;如何对java中的垃圾回收进行调优&quot;">​</a></h4><ol><li>总的来说尽量让对象在年轻代被回收，减少对象进入老年代</li><li>首先分析gc日志，当系统频繁发生full gc且内存没泄露时，可能是young gc设置太小了，导致对象过早进入老年代，还有就是young gc多少次没回收进入老年代这个阈值设置过小，或者是第三方手动调用full gc</li><li>合理配置堆内存大小、调整新生代和老年代的比例，调整垃圾回收预制，避免频繁full gc，减少长时间停顿</li></ol><h4 id="spring如何解决循环依赖" tabindex="-1">Spring如何解决循环依赖 <a class="header-anchor" href="#spring如何解决循环依赖" aria-label="Permalink to &quot;Spring如何解决循环依赖&quot;">​</a></h4><ol><li>说一下三级缓存机制，一级缓存：放的是完全初始化好的bean，二级：以及被new出来的bean但是属性还没填充的，三级：放的是能够生产某个bean的工厂对象</li><li>流程：A先被实例化出来，此时A还没完全生成好，然后Spring就将A的工厂放入三级缓存，然后A开始填充属性，发现需要B，就去创建B，B生成填充属性发现需要A就从三级缓存中找到A的工厂并拿到引用对象，然后放到二级缓存，销毁三级缓存中的A工厂，然后B拿到了A放入一级缓存，A拿到B放入一级缓存，完成</li></ol><h4 id="如何解决redis中热点key的问题" tabindex="-1">如何解决redis中热点key的问题 <a class="header-anchor" href="#如何解决redis中热点key的问题" aria-label="Permalink to &quot;如何解决redis中热点key的问题&quot;">​</a></h4><ol><li>热点key拆分成多个，散落在不同节点上</li><li>读写分离，读请求到从库，写请求到主库</li><li>多级缓存，用一些本地缓存作为缓冲</li><li>限流降级：对热点key做限流，一旦超过某个阈值则返回降级数据</li></ol><h4 id="tcp是用来解决什么问题" tabindex="-1">TCP是用来解决什么问题 <a class="header-anchor" href="#tcp是用来解决什么问题" aria-label="Permalink to &quot;TCP是用来解决什么问题&quot;">​</a></h4><ol><li>解决传输过程中的不可靠问题</li><li>传输过程中需要序列号、确认号、超时重传机制、收到消息一方需要ACK回应等</li><li>滑动窗口表示接收方还能接收多少数据，避免把对方缓冲区撑爆</li><li>连接可靠：通过三次握手和四次挥手保证双方连接状态同步，连接可靠</li></ol><h4 id="什么是限流、限流算法有哪些、怎么实现" tabindex="-1">什么是限流、限流算法有哪些、怎么实现 <a class="header-anchor" href="#什么是限流、限流算法有哪些、怎么实现" aria-label="Permalink to &quot;什么是限流、限流算法有哪些、怎么实现&quot;">​</a></h4><ol><li>计数器、滑动窗口、漏桶、令牌桶</li><li>计数器：维护一个计数器、请求来就+1，记录窗口时间内的请求数，超过阈值则拒绝，缺点无法应对突发流量，因为计数器还没来得及计数服务先被打垮了</li><li>滑动窗口：记录时间窗口内的每个请求的时间点，统计一下请求数是否超限，缺点记录每个请求时间戳，有一定内存占用</li><li>漏桶：设定一个桶的大小，请求来了先进桶，然后进桶的就会定速处理，桶满了则拒绝，缺点也是没法应对突发流量</li><li>令牌桶：桶内有一定令牌数，请求来了则拿取令牌，被拿完了就拒绝</li></ol><h4 id="spring为啥需要三级缓存-二级不够吗" tabindex="-1">Spring为啥需要三级缓存，二级不够吗 <a class="header-anchor" href="#spring为啥需要三级缓存-二级不够吗" aria-label="Permalink to &quot;Spring为啥需要三级缓存，二级不够吗&quot;">​</a></h4><ol><li>如果只是为了解决循环依赖，那确实够了，因为只要在A的bean初始化好后就将其引用代理放入二级缓存中，然后需要就拿出代理对象</li><li>这就说明了，不管是否真的有依赖循环问题，在bean初始化好后都得将其代理对象放入二级缓存中，而bean的生命周期是，AOP动态代理是在Bean初始化好后才创建的，这就违反了Bean的生命周期</li><li>所以需要引入三级缓存，把能创建bean的代理工厂先放入，等到产生循环依赖就生产代理对象，然后放入二级</li></ol><h4 id="redis的持久化机制有哪些" tabindex="-1">redis的持久化机制有哪些 <a class="header-anchor" href="#redis的持久化机制有哪些" aria-label="Permalink to &quot;redis的持久化机制有哪些&quot;">​</a></h4><ol><li>RDB和AOF，RDB：每个一段时间就将内存数据打成一个二进制文件，好处就是体积小恢复快，但是redis挂机就丢掉了，可能会丢那段时间的数据，AOF日志：每条命令都写入文件中，好处是数据安全性高，保存较完整，缺点是体积较大，恢复数据时耗时</li><li>4.0后就将两者结合起来用了，写AOF前先快照RDB一下，然后增量增加数据用AOF写入，恢复时先加载RDB部分，再回放AOF部分</li></ol><h4 id="jvm的垃圾回收算法有哪些" tabindex="-1">JVM的垃圾回收算法有哪些 <a class="header-anchor" href="#jvm的垃圾回收算法有哪些" aria-label="Permalink to &quot;JVM的垃圾回收算法有哪些&quot;">​</a></h4><ol><li>标记-清除：逐个遍历，有用就标记，没用就清除，问题是清理后东一块西一块，空间不连续，影响下一次的对象分配</li><li>复制算法：整个空间一分为二，一边先空着，回收的时候把活着的对象复制到空的那边，然后清除原本一边，缺点是一定时间内的空间浪费</li><li>标记-整理：先做标记，将一堆活着的对象往一段推，然后清除剩下的，也就解决了第一种的空间不连续问题</li></ol><h4 id="redis中缓存击穿、穿透、雪崩是什么" tabindex="-1">Redis中缓存击穿、穿透、雪崩是什么 <a class="header-anchor" href="#redis中缓存击穿、穿透、雪崩是什么" aria-label="Permalink to &quot;Redis中缓存击穿、穿透、雪崩是什么&quot;">​</a></h4><ol><li>穿透了，穿透到数据库，也就是疯狂查询一个在redis中不存在的数据，每次都请求到数据库，解决方案：redis先可以给这个不存在的数据存个空值，布隆过滤器-把所有合法key预先加载进去，请求来了先问过滤器，不存在就直接返回</li><li>击穿：某个热点key在一个时间上过期了，突然很多请求进来，全部击穿到数据库，解决方法：加锁，过期时加锁先只放一个请求过去，然后拿到数据写入缓存再释放锁，还有就是这种热点的话就定时给他刷新，达到一种一直没法过期的效果</li><li>雪崩：一堆key同时过期了，或者是redis直接挂了，解决方法：每个key都设置随机过期时间，把缓存失效时间打散，挂掉的话就主从 + 哨兵，加本地缓存、缓存预热、限流降级</li></ol>',20)])])}const b=l(r,[["render",o]]);export{u as __pageData,b as default};
